from django import formsfrom .models import Commentclass TicketForm(forms.Form):    SUBJECT_CHOICES = (        ("پیشنهاد","پیشنهاد"),        ("انتقاد","انتقاد"),        ("گزارش","گزارش"),    )    message = forms.CharField(widget=forms.Textarea, required=True)    name = forms.CharField(max_length=250, required=True)    email = forms.EmailField()    phone = forms.CharField(max_length=11, required=True)    subject = forms.ChoiceField(choices=SUBJECT_CHOICES)    def clean_phone(self):        phone = self.cleaned_data['phone']        if phone:            if not phone.isnumeric():                raise forms.ValidationError("شماره تماس باید فقط عدد باشد!")            else:                return phone        return Noneclass CommentForm(forms.ModelForm):    def clean_name(self):        name = self.cleaned_data['name']        if name:            if len(name) < 3:                raise forms.ValidationError("نام کوتاه است!")        return name    class Meta:        model = Comment        fields = ['body', 'name']class SearchForm(forms.Form):    SEARCH_CHOICES = (        ('title', 'Title'),        ('description', 'Description'),        ('author', 'Author'),    )    q = forms.CharField(        max_length=100,        required=False,        label='Search'    )    type = forms.ChoiceField(        choices=SEARCH_CHOICES,        initial='title'    )